class Solution {
    public int minMovesToMakePalindrome(String s) {
        int n = s.length();
        int[] count = new int[26];
        for (char c : s.toCharArray()) {
            count[c - 'a']++;
        }
        int moves = 0;
        for (int i = 0; i < n / 2; i++) {
            if (count[s.charAt(i) - 'a'] == 0) continue;
            count[s.charAt(i) - 'a']--;
            if (s.charAt(n - i - 1) != s.charAt(i)) {
                moves++;
                count[s.charAt(n - i - 1) - 'a']--;
            }
        }
        for (int i = 0; i < 26; i++) {
            moves += count[i] / 2;
        }
        return moves;
    }
}
